package main

import (
	"fmt"
	"sync"
)

func processTransactions(accounts map[string]int, wg *sync.WaitGroup, ch chan string) {
	defer wg.Done()
	for transaction := range ch {
		parts := strings.Split(transaction, " ")
		if len(parts) < 3 {
			continue
		}
		account := parts[0]
		amount, _ := strconv.Atoi(parts[2])
		switch parts[1] {
		case "deposit":
			accounts[account] += amount
		case "withdrawal":
			if accounts[account] >= amount {
				accounts[account] -= amount
			}
		}
	}
}

func main() {
	accounts := map[string]int{
		"account1": 100,
		"account2": 200,
	}

	ch := make(chan string)
	var wg sync.WaitGroup

	for i := 0; i < 5; i++ {
		wg.Add(1)
		go processTransactions(accounts, &wg, ch)
	}

	transactions := []string{
		"account1 deposit 50",
		"account2 withdrawal 75",
		"account1 withdrawal 30",
		"account3 deposit 100", // Non-existent account
	}

	for _, transaction := range transactions {
		ch <- transaction
	}
	close(ch)

	wg.Wait()

	fmt.Println("Final balances:", accounts)
}